Translate this C linked list implementation to Hemlock. Use Hemlock objects instead of structs, and Hemlock's alloc/free for memory management where appropriate. However, since Hemlock objects are heap-allocated by default, you can use objects directly without alloc for the nodes.

```c
#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

Node* create_node(int data) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->data = data;
    node->next = NULL;
    return node;
}

void push_front(Node** head, int data) {
    Node* node = create_node(data);
    node->next = *head;
    *head = node;
}

void print_list(Node* head) {
    Node* current = head;
    while (current != NULL) {
        printf("%d", current->data);
        if (current->next != NULL) printf(" -> ");
        current = current->next;
    }
    printf("\n");
}

int length(Node* head) {
    int count = 0;
    Node* current = head;
    while (current != NULL) {
        count++;
        current = current->next;
    }
    return count;
}

void reverse(Node** head) {
    Node* prev = NULL;
    Node* current = *head;
    Node* next = NULL;
    while (current != NULL) {
        next = current->next;
        current->next = prev;
        prev = current;
        current = next;
    }
    *head = prev;
}

int main() {
    Node* list = NULL;
    push_front(&list, 10);
    push_front(&list, 20);
    push_front(&list, 30);
    push_front(&list, 40);

    print_list(list);      // 40 -> 30 -> 20 -> 10
    printf("length: %d\n", length(list));

    reverse(&list);
    print_list(list);      // 10 -> 20 -> 30 -> 40

    return 0;
}
```

The Hemlock version should produce identical output. Use ref parameters where C uses pointer-to-pointer.
